// Validate the list of tenants
function toggleOccupants() {
    var occupantsNumber = fd.field('NumberOfTenants').value;

    fd.validators.length = [];

    if (occupantsNumber > 0) {
        $('.fd-occupants-list').show();

        fd.validators.push({
            name: 'OccupantsValidation',
            error: 'List all occupants',
            validate: function (value) {
                if (fd.control('Occupants').value.length < occupantsNumber) {
                    return false;
                }

                return true;
            },
        });
    } else {
        $('.fd-occupants-list').hide();
    }
}

// Show/hide PetInformation field and make it mandatory
function togglePetInfo() {
    var petInfo = fd.field('PetInformation');

    if (fd.field('Pets').value) {
        petInfo.hidden = false;
        petInfo.required = true;
    } else {
        petInfo.hidden = true;
        petInfo.required = false;
    }
}

fd.rendered(function () {

    //call functions when the form is rendered
    togglePetInfo();
    toggleOccupants();
    
    //call functions when field value changes
    fd.field('NumberOfTenants').$on('change', toggleOccupants);
    fd.field('Pets').$on('change', togglePetInfo);
});

